class Solution(object):
    def minZeroArray(self, nums, queries):
        n = len(nums)

        def can_zero(k):
            diff = [0] * (n + 1)
            for l, r, val in queries[:k]:
                diff[l] += val
                diff[r + 1] -= val
            coverage = 0
            for i in range(n):
                coverage += diff[i]
                if nums[i] > coverage:
                    return False
            return True

        if not can_zero(len(queries)):
            return -1

        lo, hi = 0, len(queries)
        while lo < hi:
            mid = (lo + hi) // 2
            if can_zero(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo
